/**
 * SAML Relying Party UPDATE handler (samlgw2)
 *
 * Updates RP config on samlgw2 and SP info in DynamoDB.
 */

import { PutItemCommand, QueryCommand } from '@aws-sdk/client-dynamodb';
import {
  createSamlGw2ClientFromEnv,
  buildSamlgw2ItorgId,
} from '../samlgw2-client/index.mjs';

async function getTenantInfo(tenantId, dynamodb, tenantTable) {
  const result = await dynamodb.send(new QueryCommand({
    TableName: tenantTable,
    KeyConditionExpression: 'id = :id AND begins_with(sk, :sk_prefix)',
    ExpressionAttributeValues: {
      ':id': { S: `TENANT#${tenantId}` },
      ':sk_prefix': { S: 'TENANT#' },
    },
  }));
  if (!result.Items || result.Items.length === 0) return null;
  const item = result.Items[0];
  return { orgId: item.org_id?.S };
}

async function getSamlgw2ItorgId(tenantOrgId, dynamodb, tenantTable) {
  try {
    const result = await dynamodb.send(new QueryCommand({
      TableName: tenantTable,
      KeyConditionExpression: 'id = :id AND begins_with(sk, :sk_prefix)',
      ExpressionAttributeValues: {
        ':id': { S: `ORG#${tenantOrgId}` },
        ':sk_prefix': { S: 'ORG#' },
      },
      ProjectionExpression: 'samlgw2_itorg_id',
    }));
    const stored = result.Items?.[0]?.samlgw2_itorg_id?.S;
    if (stored) return stored;
  } catch (e) {
    console.log('Failed to query org:', e.message);
  }
  return buildSamlgw2ItorgId(process.env.ACCOUNT_ID, tenantOrgId);
}

export const putResData = async (payload, dynamodb, tenantId, tenantTable, spInfoTable) => {
  console.log('samls putResData Input:', payload);

  const rpName = payload.id || payload.rpName;
  if (!rpName) throw new Error('rpName/id is required');

  const tenantInfo = await getTenantInfo(tenantId, dynamodb, tenantTable);
  if (!tenantInfo?.orgId) throw new Error('Tenant has no org');

  const itorgId = await getSamlgw2ItorgId(tenantInfo.orgId, dynamodb, tenantTable);
  const customerName = tenantId.toLowerCase();

  // Update RP on samlgw2 if config fields are provided
  if (payload.claim_mappings || payload.saml || payload.sp_metadata_url || payload.display_name) {
    const rpConfig = {};
    if (payload.display_name) rpConfig.display_name = payload.display_name;
    if (payload.login_url || payload.serviceUrl) rpConfig.login_url = payload.login_url || payload.serviceUrl;
    if (payload.logo_url || payload.logoUrl) rpConfig.logo_url = payload.logo_url || payload.logoUrl;
    if (payload.sp_metadata_url) rpConfig.sp = { metadata_url: payload.sp_metadata_url };
    if (payload.claim_mappings) rpConfig.claim_mappings = payload.claim_mappings;
    if (payload.saml) rpConfig.saml = payload.saml;

    try {
      const samlgw2 = createSamlGw2ClientFromEnv();
      await samlgw2.createRelyingParty(itorgId, customerName, rpName.toLowerCase(), rpConfig);
      console.log(`RP '${rpName}' updated on samlgw2`);
    } catch (gw2Error) {
      console.error('samlgw2 update RP error (non-fatal):', gw2Error.message);
    }
  }

  // Update SP info in DynamoDB
  const samlgw2 = createSamlGw2ClientFromEnv();
  const idpMetadataUrl = samlgw2.getIdpMetadataUrl(itorgId, customerName, rpName.toLowerCase());
  const callbackUrl = samlgw2.getOidcCallbackUrl(itorgId, customerName, rpName.toLowerCase());

  const params = {
    Item: {
      id: { S: `#SAML#${rpName}` },
      name: { S: payload.name || payload.display_name || '' },
      logoUrl: { S: payload.logoUrl || payload.logo_url || '' },
      serviceUrl: { S: payload.serviceUrl || payload.login_url || '' },
      released: { BOOL: payload.released ? true : false },
      template: { S: payload.template || 'custom' },
      rpName: { S: rpName },
      idpMetadataUrl: { S: idpMetadataUrl },
      callbackUrl: { S: callbackUrl },
      metadataUrl: { S: payload.metadataUrl || payload.sp_metadata_url || '' },
    },
    ReturnConsumedCapacity: 'TOTAL',
    TableName: spInfoTable,
  };

  await dynamodb.send(new PutItemCommand(params));
  console.log('SP info updated in DynamoDB');

  return payload;
};

export default putResData;
